// Script Continued Below
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
   if (isLoading || newValue === '') {
      return;
   }

   // RJ - STRY0064119 - when box is checked, change the label
	// TODO, INTERNATIONALIZE
	if(newValue == 'true' || newValue ==true){
		// STRY0071512 - FIX

		g_form.setLabelOf('u_create_subtasks_in_serial', 'Serial - uncheck for Parallel Subtasks');
	}else{
		g_form.setLabelOf('u_create_subtasks_in_serial', 'Parallel - check for Serial Subtasks');
	}
}
